# Utility functions for shape operations
from shapes import Shape, Rectangle, Circle
from interfaces import IDrawable, IScalable, IMeasurable

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def total_perimeter(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.perimeter()
    return total

def create_square(name: str, side: float) -> Rectangle:
    return Rectangle(name, side, side)

def describe_all(shapes: list[Shape]) -> list[str]:
    result: list[str] = []
    for shape in shapes:
        result.append(shape.describe())
    return result
